   371→          if (dbUrl && finalSessionId && fullResponse) {
   372→            const db = neon(dbUrl);
   373→            db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'omega', ${fullResponse})`
   374→              .catch(e => console.error('[OmegA] DB save error', e));
   375→          }
   376→
   377→          controller.close();
   378→        } catch (err) {
   379→          console.error('[OmegA] Stream error', err);
   380→          controller.error(err);
   381→        }
   382→      }
   383→    });
   384→
   385→    return new NextResponse(customStream, {
   386→      headers: {
   387→        'Content-Type': 'text/plain; charset=utf-8',
   388→        'X-Session-Id': finalSessionId || '',
   389→        'X-Provider': provider,
   390→      }
   391→    });
   392→
   393→  } catch (err) {
   394→    console.error('[OmegA] POST error', err);
   395→    return NextResponse.json({ error: String(err) }, { status: 500 });
   396→  }
   397→}
