    27→
    28→const WAKE_WORDS = ['mega', 'omega'];
    29→const FOLLOW_UP_MS = 25_000;
    30→const MIN_SPEECH_CHARS = 3;
    31→const SILENCE_COMMIT_MS = 1400;
    32→
    33→// Shared helper: drive an audio level meter from an AnalyserNode
    34→function startLevelTick(
    35→  analyser: AnalyserNode,
    36→  setLevel: (v: number) => void,
    37→  animRef: React.MutableRefObject<number | null>,
    38→) {
    39→  const buf = new Uint8Array(analyser.frequencyBinCount);
    40→  const tick = () => {
    41→    analyser.getByteFrequencyData(buf);
    42→    const avg = buf.reduce((a, b) => a + b, 0) / buf.length;
    43→    setLevel(Math.min(avg / 80, 1));
    44→    animRef.current = requestAnimationFrame(tick);
    45→  };
    46→  tick();
    47→}
