    49→export function useVoiceEngine({
    50→  onTranscript,
    51→  onTTSStart,
    52→  onTTSEnd,
    53→  followUpWindowMs = FOLLOW_UP_MS,
    54→  ttsUrl = '/api/tts',
    55→  autoStart = true,
    56→}: VoiceEngineOptions): VoiceEngineReturn {
    57→  const [voiceState, setVoiceState] = useState<VoiceState>('dormant');
    58→  const [interim, setInterim] = useState('');
    59→  const [micLevel, setMicLevel] = useState(0);
    60→  const [ttsLevel, setTtsLevel] = useState(0);
    61→  const [supported, setSupported] = useState(false);
    62→
    63→  const stateRef = useRef<VoiceState>('dormant');
    64→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
    65→  const recogRef = useRef<any>(null);
    66→  const followUpTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
    67→  const audioCtxRef = useRef<AudioContext | null>(null);
    68→  const micStreamRef = useRef<MediaStream | null>(null);
    69→  const analyserRef = useRef<AnalyserNode | null>(null);
    70→  const micAnimRef = useRef<number | null>(null);
    71→  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
    72→  const ttsCtxRef = useRef<AudioContext | null>(null);
    73→  const ttsAnimRef = useRef<number | null>(null);
    74→  const mutedRef = useRef(false);
    75→  const restartTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    76→
    77→  // Stale-closure avoidance: callbacks read stateRef instead of voiceState
