   106→
   107→  const stopMicAnalyzer = useCallback(() => {
   108→    if (micAnimRef.current) {
   109→      cancelAnimationFrame(micAnimRef.current);
   110→      micAnimRef.current = null;
   111→      setMicLevel(0);
   112→    }
   113→  }, []);
   114→
   115→  // ── Follow-up window ──────────────────────────────────────────────────────
   116→  const clearFollowUp = useCallback(() => {
   117→    if (followUpTimer.current) clearTimeout(followUpTimer.current);
   118→  }, []);
   119→
   120→  const enterFollowUp = useCallback(() => {
   121→    setState('followup');
   122→    clearFollowUp();
   123→    followUpTimer.current = setTimeout(() => {
   124→      if (stateRef.current === 'followup') setState('dormant');
   125→    }, followUpWindowMs);
   126→  }, [setState, clearFollowUp, followUpWindowMs]);
   127→
   128→  // ── TTS playback ──────────────────────────────────────────────────────────
   129→  const stopSpeaking = useCallback(() => {
   130→    ttsSourceRef.current?.stop();
   131→    ttsSourceRef.current = null;
   132→    if (ttsAnimRef.current) {
   133→      cancelAnimationFrame(ttsAnimRef.current);
   134→      ttsAnimRef.current = null;
   135→    }
