   137→    if (ttsCtxRef.current) {
   138→      ttsCtxRef.current.close().catch(() => {});
   139→      ttsCtxRef.current = null;
   140→    }
   141→    setTtsLevel(0);
   142→  }, []);
   143→
   144→  const speakText = useCallback(async (text: string): Promise<void> => {
