   185→        ctx.close().catch(() => {});
   186→        ttsCtxRef.current = null;
   187→        onTTSEnd?.();
   188→        enterFollowUp();
   189→      };
   190→    } catch (e) {
   191→      console.warn('[VoiceEngine] TTS error:', e);
   192→      onTTSEnd?.();
