   194→    }
   195→  }, [ttsUrl, stopSpeaking, setState, enterFollowUp, onTTSStart, onTTSEnd]);
   196→
   197→  // ── Speech recognition ────────────────────────────────────────────────────
   198→  const stopRecognition = useCallback(() => {
