   259→          setState('listening');
   260→          startMicAnalyzer();
   261→        }
   262→      }
   263→    };
   264→
   265→    r.onspeechstart = () => {
   266→      if (stateRef.current === 'dormant') return;
   267→      if (stateRef.current === 'followup') {
   268→        clearFollowUp();
   269→        setState('listening');
   270→        startMicAnalyzer();
   271→      }
   272→    };
   273→
   274→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
   275→    r.onerror = (e: any) => {
   276→      if (e.error === 'no-speech' || e.error === 'aborted') return;
