   288→      }
   289→    };
   290→
   291→    try { r.start(); } catch { /* already running */ }
   292→  }, [stopRecognition, stopMicAnalyzer, setState, startMicAnalyzer, onTranscript, clearFollowUp]);
   293→
   294→  // ── Public controls ───────────────────────────────────────────────────────
   295→  const wakeUp = useCallback(() => {
   296→    clearFollowUp();
   297→    setState('listening');
   298→    startMicAnalyzer();
   299→  }, [setState, clearFollowUp, startMicAnalyzer]);
   300→
   301→  const toggle = useCallback(() => {
   302→    if (stateRef.current === 'dormant') {
