   305→      startRecognition();
   306→    } else {
   307→      mutedRef.current = true;
   308→      stopRecognition();
   309→      stopSpeaking();
   310→      stopMicAnalyzer();
   311→      clearFollowUp();
   312→      setState('dormant');
   313→    }
   314→  }, [wakeUp, startRecognition, stopRecognition, stopSpeaking, stopMicAnalyzer, clearFollowUp, setState]);
   315→
   316→  // ── Init ──────────────────────────────────────────────────────────────────
   317→  useEffect(() => {
   318→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
